@dataclass
class Dependency:
    """Represents a single dependency with version and hash information."""
    name: str
    version: str
    hashes: list = field(default_factory=list)
    extras: list = field(default_factory=list)
    markers: str = ""
    is_direct: bool = True

    def to_requirements_line(self) -> str:
        """Generate a requirements.txt compatible line with hashes."""
        extras_str = f"[{','.join(self.extras)}]" if self.extras else ""
        markers_str = f" ; {self.markers}" if self.markers else ""
        line = f"{self.name}{extras_str}=={self.version}{markers_str}"
        if self.hashes:
            hash_lines = " \\\n    ".join(
                f"--hash={h}" for h in self.hashes
            )
            line = f"{line} \\\n    {hash_lines}"
        return line


