    def verify_lockfile(self, lockfile: Optional[str] = None):
        """
        Verify the integrity of a lock file.

        Checks:
        - All dependencies are pinned to exact versions
        - All dependencies have hash specifications
        - No references to untrusted indexes
        - File hasn't been tampered with
        """
        if lockfile is None:
            lockfile = self.config["requirements_txt"]

        filepath = self._safe_path(lockfile)
        if not filepath.exists():
            raise FileNotFoundError(f"Lock file not found: {filepath}")

        logger.info("Verifying lock file: %s", lockfile)
        issues = []
        dependencies = []

        content = filepath.read_text(encoding="utf-8")
        lines = content.splitlines()

        i = 0
        while i < len(lines):
            line = lines[i].strip()

            # Skip comments and empty lines
            if not line or line.startswith("#") or line.startswith("--"):
                # Check for suspicious index URLs in comments/options
                if "--index-url" in line or "--extra-index-url" in line:
                    url_match = re.search(r"https?://\S+", line)
                    if url_match:
                        url = url_match.group()
                        if url not in self.config["allowed_indexes"]:
                            issues.append(
                                f"⚠️  Untrusted index URL found: {url}"
                            )
                i += 1
                continue

            # Collect continuation lines
            full_line = line
            while full_line.endswith("\\") and i + 1 < len(lines):
                i += 1
                full_line = full_line[:-1] + " " + lines[i].strip()

            # Parse dependency line
            dep_match = re.match(
                r"^([a-zA-Z0-9_\-\.]+(?:\[[^\]]+\])?)\s*==\s*([^\s;\\]+)",
                full_line,
            )
            if dep_match:
                name = dep_match.group(1)
                version = dep_match.group(2)
                has_hash = "--hash=" in full_line
                hash_count = full_line.count("--hash=")

                dependencies.append({
                    "name": name,
                    "version": version,
                    "has_hash": has_hash,
                    "hash_count": hash_count,
                })

                if not has_hash:
                    issues.append(
                        f"⚠️  Missing hash for: {name}=={version}"
                    )
            elif re.match(r"^[a-zA-Z0-9_\-\.]+", full_line):
                # Dependency without exact pin
                dep_name = re.match(r"^([a-zA-Z0-9_\-\.]+)", full_line).group(1)
                if "==" not in full_line:
                    issues.append(
                        f"❌ Unpinned dependency: {dep_name} (line: {full_line[:80]})"
                    )

            i += 1

        # Report results
        logger.info("Found %d dependencies", len(dependencies))

        if issues:
            logger.warning("Found %d issues:", len(issues))
            for issue in issues:
                logger.warning("  %s", issue)
            return False
        else:
            logger.info("✅ Lock file verification passed. All dependencies are pinned with hashes.")
            return True

    def audit_dependencies(self):
        """
        Audit dependencies for known security vulnerabilities.

        Uses pip-audit (maintained by PyPA) to check against the
        Python Packaging Advisory Database.
        """
        if not self._check_tool_installed("pip-audit"):
            logger.info("Installing pip-audit...")
            self._run_command(
                [sys.executable, "-m", "pip", "install", "pip-audit"]
            )

        req_file = self._safe_path(self.config["requirements_txt"])
        if not req_file.exists():
            raise FileNotFoundError(
                f"Lock file not found: {req_file}. Generate it first."
            )

        logger.info("🔍 Auditing dependencies for vulnerabilities...")

        cmd = [
            "pip-audit",
            "-r", self.config["requirements_txt"],
            "--format=json",
            "--strict",
        ]

        result = self._run_command(cmd, check=False)

        if result.returncode == 0:
            logger.info("✅ No known vulnerabilities found.")
            return True
        else:
            logger.warning("⚠️  Vulnerabilities detected!")
            try:
                audit_data = json.loads(result.stdout)
                for dep in audit_data.get("dependencies", []):
                    for vuln in dep.get("vulns", []):
                        logger.warning(
                            "  📦 %s==%s: %s (%s) - Fix: %s",
                            dep["name"],
                            dep["version"],
                            vuln.get("id", "Unknown"),
                            vuln.get("description", "No description")[:100],
                            vuln.get("fix_versions", "No fix available"),
                        )
            except (json.JSONDecodeError, KeyError):
                # Fall back to text output
                if result.stdout:
                    logger.warning(result.stdout[:3000])
            return False

    def freeze_current_environment(self):
        """
        Capture the current environment state as a reference.

        Outputs a JSON file with all installed packages, versions, and hashes.
        """
        result = self._run_command(
            [sys.executable, "-m", "pip", "list", "--format=json"]
        )

        packages = json.loads(result.stdout)
        freeze_data = {
            "generated_at": datetime.now(timezone.utc).isoformat(),
            "python_version": f"{sys.version_info.major}.{sys.version_info.minor}.{sys.version_info.micro}",
            "platform": sys.platform,
            "packages": {},
        }

        for pkg in packages:
            name = pkg["name"]
            version = pkg["version"]
            freeze_data["packages"][name] = {
                "version": version,
            }

        output_path = self._safe_path("environment_freeze.json")
        self._backup_file(output_path)

        output_path.write_text(
            json.dumps(freeze_data, indent=2, sort_keys=True),
            encoding="utf-8",
        )
        logger.info("✅ Environment frozen to: %s", output_path)
        logger.info("   Total packages: %d", len(freeze_data["packages"]))

    def diff_lockfiles(self, file1: str, file2: str):
        """
        Compare two lock files and show differences.

        Useful for reviewing dependency updates before merging.
        """
        path1 = self._safe_path(file1)
        path2 = self._safe_path(file2)

        if not path1.exists():
            raise FileNotFoundError(f"File not found: {path1}")
        if not path2.exists():
            raise FileNotFoundError(f"File not found: {path2}")

        deps1 = self._parse_requirements_file(path1)
        deps2 = self._parse_requirements_file(path2)

        names1 = set(deps1.keys())
        names2 = set(deps2.keys())

        added = names2 - names1
        removed = names1 - names2
        common = names1 & names2

        changed = []
        for name in sorted(common):
            if deps1[name] != deps2[name]:
                changed.append((name, deps1[name], deps2[name]))

        print(f"\n📊 Dependency Diff: {file1} → {file2}")
        print("=" * 60)

        if added:
            print(f"\n➕ Added ({len(added)}):")
            for name in sorted(added):
                print(f"   {name}=={deps2[name]}")

        if removed:
            print(f"\n➖ Removed ({len(removed)}):")
            for name in sorted(removed):
                print(f"   {name}=={deps1[name]}")

        if changed:
            print(f"\n🔄 Changed ({len(changed)}):")
            for name, old_ver, new_ver in changed:
                print(f"   {name}: {old_ver} → {new_ver}")

        if not added and not removed and not changed:
            print("\n✅ No differences found.")

        print()

