    @staticmethod
    def _parse_requirements_file(filepath: Path) -> dict:
        """Parse a requirements.txt file into a dict of {name: version}."""
        deps = {}
        content = filepath.read_text(encoding="utf-8")
        for line in content.splitlines():
            line = line.strip()
            if not line or line.startswith("#") or line.startswith("--"):
                continue
            # Remove continuation and hash parts
            line = line.split("\\")[0].strip()
            match = re.match(
                r"^([a-zA-Z0-9_\-\.]+)(?:\[[^\]]+\])?\s*==\s*([^\s;]+)",
                line,
            )
            if match:
                deps[match.group(1).lower()] = match.group(2)
        return deps

    @staticmethod
    def _add_lockfile_header(filepath: Path):
        """Add a metadata header to the lock file."""
        content = filepath.read_text(encoding="utf-8")
        header = (
            f"#\n"
            f"# This file is autogenerated by dependency_manager.py\n"
            f"# Generated at: {datetime.now(timezone.utc).isoformat()}\n"
            f"# Python: {sys.version_info.major}.{sys.version_info.minor}.{sys.version_info.micro}\n"
            f"#\n"
            f"# DO NOT EDIT MANUALLY. Use dependency_manager.py to update.\n"
            f"#\n"
        )
        # Don't duplicate headers
        if "autogenerated by dependency_manager" not in content:
            filepath.write_text(header + "\n" + content, encoding="utf-8")

    @staticmethod
    def _print_lockfile_stats(filepath: Path):
        """Print statistics about a lock file."""
        content = filepath.read_text(encoding="utf-8")
        dep_count = 0
        hash_count = 0
        for line in content.splitlines():
            line = line.strip()
            if re.match(r"^[a-zA-Z0-9_\-\.]+.*==", line):
                dep_count += 1
            if "--hash=" in line:
                hash_count += 1

        logger.info(
            "   📦 Dependencies: %d | 🔒 Hashes: %d | 📄 Size: %d bytes",
            dep_count,
            hash_count,
            filepath.stat().st_size,
        )

